1	import { Link } from "react-router-dom";
2	import { StatusBadge } from "@/components/ui/StatusBadge";
3	import type { AnalyticsInterval, MarketSummary } from "@/lib/api/types";
4	import { formatCurrency, timeUntil } from "@/lib/utils/format";
5	
6	const INTERVAL_OPTIONS: AnalyticsInterval[] = ["day", "hour"];
7	
8	interface AnalyticsFiltersProps {
9	  markets: MarketSummary[];
10	  selectedMarketId: string;
11	  interval: AnalyticsInterval;
12	  selectedMarket?: MarketSummary;
13	  onMarketChange: (marketId: string) => void;
14	  onIntervalChange: (interval: AnalyticsInterval) => void;
15	}
16	
17	export function AnalyticsFilters({
18	  markets,
19	  selectedMarketId,
20	  interval,
21	  selectedMarket,
22	  onMarketChange,
23	  onIntervalChange,
24	}: AnalyticsFiltersProps) {
25	  return (
26	    <section style={cardStyle}>
27	      <div style={{ display: "grid", gap: "var(--space-md)" }}>
28	        <div style={headerRowStyle}>
29	          <div style={{ display: "grid", gap: "var(--space-xs)" }}>
30	            <div style={eyebrowStyle}>Selected Market</div>
31	            <div
32	              style={{
33	                display: "flex",
34	                gap: "var(--space-sm)",
35	                alignItems: "center",
36	                flexWrap: "wrap",
37	              }}
38	            >
39	              <h2 style={{ fontSize: "1.2rem", fontWeight: 600 }}>
40	                {selectedMarket?.title ?? "Choose a market"}
41	              </h2>
42	              {selectedMarket && <StatusBadge status={selectedMarket.status} />}
43	            </div>
44	            {selectedMarket && (
45	              <div style={metaRowStyle}>
46	                <span>Liquidity {formatCurrency(selectedMarket.liquidity)}</span>
47	                <span>Volume {formatCurrency(selectedMarket.volume)}</span>
48	                <span>Expires {timeUntil(selectedMarket.expires_at)}</span>
49	              </div>
50	            )}
51	          </div>
52	          {selectedMarket && (
53	            <Link to={`/markets/${selectedMarket.id}`} style={actionLinkStyle}>
54	              Open Market
55	            </Link>
56	          )}
57	        </div>
58	
59	        <div
60	          style={{
61	            display: "flex",
62	            gap: "var(--space-md)",
63	            alignItems: "end",
64	            flexWrap: "wrap",
65	          }}
66	        >
67	          <label style={fieldStyle}>
68	            <span style={labelStyle}>Market</span>
69	            <select
70	              aria-label="Market"
71	              data-testid="market-select"
72	              value={selectedMarketId}
73	              onChange={(event) => onMarketChange(event.target.value)}
74	              style={selectStyle}
75	            >
76	              {markets.map((market) => (
77	                <option key={market.id} value={market.id}>
78	                  {market.title}
79	                </option>
80	              ))}
81	            </select>
82	          </label>
83	
84	          <div style={fieldStyle}>
85	            <span style={labelStyle}>Interval</span>
86	            <div style={{ display: "flex", gap: "var(--space-sm)", flexWrap: "wrap" }}>
87	              {INTERVAL_OPTIONS.map((option) => {
88	                const active = option === interval;
89	                return (
90	                  <button
91	                    key={option}
92	                    type="button"
93	                    onClick={() => onIntervalChange(option)}
94	                    style={{
95	                      ...intervalButtonStyle,
96	                      borderColor: active ? "var(--color-primary)" : "var(--color-border)",
97	                      background: active ? "rgba(99, 102, 241, 0.18)" : "var(--color-bg)",
98	                      color: active ? "var(--color-text)" : "var(--color-text-muted)",
99	                    }}
100	                  >
101	                    {option === "day" ? "Day" : "Hour"}
102	                  </button>
103	                );
104	              })}
105	            </div>
106	          </div>
107	        </div>
108	      </div>
109	    </section>
110	  );
111	}
112	
