114	  padding: "var(--space-lg)",
115	  borderRadius: "var(--radius-lg)",
116	  border: "1px solid var(--color-border)",
117	  background:
118	    "linear-gradient(180deg, rgba(99, 102, 241, 0.08), rgba(15, 17, 23, 0.9))",
119	};
120	
