148	  border: "1px solid var(--color-border)",
149	  background: "rgba(15, 17, 23, 0.75)",
150	  color: "var(--color-text)",
151	  fontSize: "0.85rem",
152	  fontWeight: 600,
153	};
154	
155	const fieldStyle: React.CSSProperties = {
156	  display: "grid",
157	  gap: "var(--space-xs)",
158	  minWidth: 220,
159	};
160	
