170	  padding: "10px 12px",
171	  borderRadius: "var(--radius-md)",
172	  border: "1px solid var(--color-border)",
173	  background: "rgba(15, 17, 23, 0.92)",
174	  color: "var(--color-text)",
175	  fontSize: "0.9rem",
176	};
177	
178	const intervalButtonStyle: React.CSSProperties = {
179	  padding: "10px 14px",
